2.query:
// 1. Create timeseries of captured and estimated span counts for fullstack-adaptive
timeseries {
  spans_sampled = sum(dt.sfm.spans.ingest.count, filter:licensing_type=="fullstack-adaptive"),
  spans_processed = sum(dt.sfm.spans.ingest.estimated_count, filter:licensing_type=="fullstack-adaptive")
}, nonempty:true

// 2. Compute capture rate and cap it at 100%
| fieldsAdd capture_rate = spans_sampled[] / spans_processed[] * 100
| fieldsAdd capture_rate = if(capture_rate[] > 100, 100, else: capture_rate[])

// 3. Remove intermediate fields
| fieldsRemove spans_sampled, spans_processed

3.query:
// 1. Create timeseries with billing limits and usable adaptive volume
timeseries {
  included_limit = avg(dt.billing.traces.maximum_included_fullstack_volume_per_minute),
  configured_limit = avg(dt.billing.traces.maximum_configured_fullstack_volume_per_minute),
  adaptive_limit = avg(dt.sfm.atm.usable_adaptive_trace_volume_per_minute)
}, interval:1h, nonempty:true

// 2. Join adaptive span data
| join [
  timeseries {
    spans_sampled = sum(dt.sfm.spans.ingest.count),
    spans_processed = sum(dt.sfm.spans.ingest.estimated_count),
    ingested_bytes_adaptive = sum(dt.sfm.spans.ingest.size)
  }, interval:1h, nonempty:true, filter:licensing_type=="fullstack-adaptive"
], on:{timeframe}, fields:{spans_sampled, spans_processed, ingested_bytes_adaptive}

// 3. Join fixed-rate span data
| join [
  timeseries {
    ingested_bytes_fixed = sum(dt.sfm.spans.ingest.size, filter:licensing_type=="fullstack-fixed-rate", default:0)
  }, interval:1h, nonempty:true
], on:{timeframe}, fields:{ingested_bytes_fixed}

// 4. Scale per-minute limits to interval and compute capture rate
| fieldsAdd intervalInMinutes = toLong(interval) / 60000000000
| fieldsAdd configured_limit = configured_limit[] * intervalInMinutes
| fieldsAdd included_limit = included_limit[] * intervalInMinutes
| fieldsAdd adaptive_limit = adaptive_limit[] * intervalInMinutes
| fieldsAdd capture_rate = spans_sampled[] / spans_processed[]
| fieldsAdd capture_rate = if(capture_rate[] > 1, 1, else: capture_rate[])
| fieldsRemove spans_processed, spans_sampled

// 5. Compute potential (dropped) adaptive bytes
| fieldsAdd potential_bytes_adaptive = (ingested_bytes_adaptive[] / capture_rate[]) - ingested_bytes_adaptive[]
| fieldsRemove capture_rate

4.query:
// 1. Create timeseries of ingested bytes grouped by licensing type
timeseries {
  ingested_bytes_sum = sum(dt.sfm.spans.ingest.size)
}, nonempty:true, interval:1h, by:{licensing_type}

10.query:
// 1. Create timeseries of the configured Full-Stack trace volume limit
timeseries {
  configured_limit = avg(dt.billing.traces.maximum_configured_fullstack_volume_per_minute)
}, interval:15m, nonempty:true

// 2. Scale per-minute limit to interval
| fieldsAdd intervalInMinutes = toLong(interval) / 60000000000
| fieldsAdd configured_limit = configured_limit[] * intervalInMinutes

// 3. Join Full-Stack ingest events
| join [
  fetch dt.system.events
  | filter event.type == "Traces - Ingest & Process"
  | filter licensing_type == "fullstack-adaptive" or licensing_type == "fullstack-fixed-rate"
  | makeTimeseries ingested_bytes_sum = sum(ingested_bytes), time: usage.start, interval:15m, nonempty:true
], on:{timeframe}, fields:{ingested_bytes_sum}

// 4. Compute volume used percentage
| fieldsAdd volume_used = ingested_bytes_sum[] / configured_limit[] * 100
| fieldsRemove configured_limit, ingested_bytes_sum

11.query:
// 1. Fetch Full-Stack trace ingest events
fetch dt.system.events

// 2. Filter to Full-Stack ingest events
| filter event.type == "Traces - Ingest & Process"
| filter licensing_type == "fullstack-adaptive" or licensing_type == "fullstack-fixed-rate"

// 3. Create timeseries of bytes and spans by licensing type
| makeTimeseries {
  ingested_bytes_sum = sum(ingested_bytes),
  ingested_spans_sum = sum(ingested_spans)
}, time: usage.start, interval:15m, by:{licensing_type}, nonempty:true

// 4. Compute average span size
| fieldsAdd avg_span_size = ingested_bytes_sum[] / ingested_spans_sum[]
| fieldsRemove ingested_bytes_sum, ingested_spans_sum

12.query:
// 1. Create timeseries of Full-Stack Monitoring usage
timeseries contributing_gib = sum(dt.billing.full_stack_monitoring.usage), interval:15m, nonempty:true

// 2. Normalize to contributing GiB per hour
| fieldsAdd intervalInMinutes = toLong(interval) / 60000000000
| fieldsAdd contributing_gib = contributing_gib[] * (60 / intervalInMinutes)

21.query:
// 1. Fetch Full-Stack adaptive trace ingest events
fetch dt.system.events

// 2. Filter to fullstack-adaptive ingest events
| filter event.type == "Traces - Ingest & Process"
| filter licensing_type == "fullstack-adaptive"

// 3. Create timeseries of ingested bytes
| makeTimeseries ingested_bytes_sum = sum(ingested_bytes), time: usage.start, interval:15m, nonempty:true

// 4. Join with billing limits
| join [
  timeseries {
    included_limit = avg(dt.billing.traces.maximum_included_fullstack_volume_per_minute),
    configured_limit = avg(dt.billing.traces.maximum_configured_fullstack_volume_per_minute)
  }, interval:15m, nonempty:true
  | fieldsAdd intervalInMinutes = toLong(interval) / 60000000000
  | fieldsAdd included_limit = included_limit[] * intervalInMinutes
  | fieldsAdd configured_limit = configured_limit[] * intervalInMinutes
  | fieldsAdd billable = if(configured_limit[] - included_limit[] > 0, true, else: false)
], kind:outer, on:{timeframe}, fields:{included_limit, configured_limit, billable}

// 5. Compute included ingest and billing amount
| fieldsAdd included_ingested_byte_sum = if(billable[], included_limit[], else: ingested_bytes_sum[])
| fieldsAdd billing_amount = if(billable[], ingested_bytes_sum[] - included_limit[], else: 0)
| fieldsRemove billable, ingested_bytes_sum

28.query:
// 1. Create timeseries with billing limits
timeseries {
  included_limit_min = avg(dt.billing.traces.maximum_included_fullstack_volume_per_minute)
}, interval:15m, nonempty:true

// 2. Scale limits to interval and apply calculator factor
| fieldsAdd intervalInMinutes = toLong(interval) / 60000000000
| fieldsAdd included_limit = included_limit_min[] * intervalInMinutes
| fieldsAdd predicted_configured_limit = included_limit_min[] * intervalInMinutes * toDouble($CalculatorExtraIngestFactor)
| fieldsRemove included_limit_min

// 3. Join with fullstack-adaptive span data
| join [
  timeseries {
    spans_sampled = sum(dt.sfm.spans.ingest.count),
    spans_processed = sum(dt.sfm.spans.ingest.estimated_count),
    ingested_bytes_sum = sum(dt.sfm.spans.ingest.size)
  }, filter:licensing_type=="fullstack-adaptive", interval:15m, nonempty:true
], on:{timeframe}, kind:outer, fields:{spans_sampled, spans_processed, ingested_bytes_sum}

// 4. Compute capture rate
| fieldsAdd captureRate = spans_sampled[] / spans_processed[]
| fieldsAdd captureRate = if(captureRate[] > 1, 1, else: captureRate[])
| fieldsRemove spans_sampled, spans_processed

// 5. Compute predicted billing amount with Extended trace ingest simulation
| fieldsAdd maximum_potential_ingestable_trace_data = ingested_bytes_sum[] / captureRate[]
| fieldsAdd min_overage = ingested_bytes_sum[] - included_limit[]
| fieldsAdd min_overage = if(min_overage[] > 0, min_overage[], else: 0)
| fieldsAdd extra_ingest_volume = predicted_configured_limit[] - included_limit[]
| fieldsAdd predicted_billing_amount = maximum_potential_ingestable_trace_data[] - included_limit[]
| fieldsAdd predicted_billing_amount = if(predicted_billing_amount[] > 0, predicted_billing_amount[], else: 0)
| fieldsAdd predicted_billing_amount = if(predicted_billing_amount[] > extra_ingest_volume[], extra_ingest_volume[], else: predicted_billing_amount[])
| fieldsAdd predicted_billing_amount = if(min_overage[] > predicted_billing_amount[], min_overage[], else: predicted_billing_amount[])
| fieldsAdd predicted_billing_amount = if(toDouble($CalculatorExtraIngestFactor) > 1.0, predicted_billing_amount[], else: 0)
| fieldsAdd included_ingested_byte_sum = if(predicted_billing_amount[] > 0, included_limit[], else: ingested_bytes_sum[])

// 6. Compute predicted capture rate
// If total potential traffic fits within the configured limit, capture rate is 100%.
// Otherwise it is the ratio of configured limit to total potential traffic.
| fieldsAdd predicted_capture_rate = if(maximum_potential_ingestable_trace_data[] <= predicted_configured_limit[], 100,
  else: predicted_configured_limit[] / maximum_potential_ingestable_trace_data[] * 100)
| fields predicted_configured_limit, included_limit, included_ingested_byte_sum, predicted_capture_rate, predicted_billing_amount, timeframe, interval
